import Foundation

// 优化 1：使用 enum 作为命名空间，避免全局变量污染
public enum PinyinHelper {
    static let hanziStart: UInt32 = 19968
    // static let hanziCount: UInt32 = 20902 // 如果通过数组长度判断，这个变量其实可以省略
    
    // 优化 2：将长字符串直接转换为 [UInt8] 数组（因为全是 ASCII 字母）
    // 这不仅解决了 String 无法直接通过 Int 下标访问的问题，还将查找时间从 O(N) 降到了真正的 O(1)
    static let firstLetterArray: [UInt8] = Array("".utf8) // 请在这里填入你完整的字符串，使用  来消除实际换行

    // 优化 3：直接传入 Character 会比在外部取 utf16 更安全
    public static func pinyinFirstLetter(for hanzi: Character) -> Character {
        // 获取字符的 Unicode 标量值
        guard let scalar = hanzi.unicodeScalars.first else { return hanzi }
        let value = scalar.value
        
        let index = Int(value - hanziStart)
        
        // 安全校验：确保索引大于 0 且不越界
        if index >= 0 && index < firstLetterArray.count {
            // 将 UInt8 转回 Character
            return Character(UnicodeScalar(firstLetterArray[index]))
        } else {
            return hanzi
        }
    }
}

public extension String {
    func stringPinyinFirstLetter(uppercase: Bool = true) -> String {
        guard let firstChar = self.first else {
            return ""
        }
        
        // 调用我们封装的 Helper
        let pinyinChar = PinyinHelper.pinyinFirstLetter(for: firstChar)
        let result = String(pinyinChar)
        
        return uppercase ? result.uppercased() : result.lowercased()
    }
    
    func containsUpperCaseLetters() -> Bool {
        // 优化 4：使用高阶函数 contains(where:)，更加 Swifty 且高效
        return self.contains(where: { $0.isUppercase })
    }
}

public extension Dictionary {
    func containsKey(_ key: Key) -> Bool {
        // 优化 5：直接使用 keys.contains() 语意更加明确
        return self.keys.contains(key)
    }
}
